interface CartTotals {
  subtotal: number;
  discount: number;
  tax: number;
  shipping: number;
  total: number;
}

function calculateCartTotals(cart: Cart): CartTotals {
  const TAX_RATE = 0.1925;
  const SHIPPING_THRESHOLD = 25000;
  const SHIPPING_COST = 1500;
  const PROMO_DISCOUNT_RATE = 0.10;

  // Calcul du sous-total
  const subtotal = cart.items.reduce(
    (sum, item) => sum + (item.unitPrice * item.quantity),
    0
  );

  // Application du code promo (si présent)
  let discount = 0;
  if (cart.promoCode === 'PROMO10') {
    discount = subtotal * PROMO_DISCOUNT_RATE;
  }

  const afterDiscount = subtotal - discount;

  // Calcul de la TVA
  const tax = afterDiscount * TAX_RATE;

  // Calcul des frais de livraison
  const shipping = afterDiscount >= SHIPPING_THRESHOLD ? 0 : SHIPPING_COST;

  // Total final
  const total = afterDiscount + tax + shipping;

  return {
    subtotal,
    discount,
    tax,
    shipping,
    total
  };
}
