@Entity()
export class Coupon {
  @PrimaryGeneratedColumn()
  id: number;

  @Column({ unique: true })
  code: string;

  @Column({ type: 'enum', enum: ['PERCENT', 'FIXED', 'FREE_SHIPPING'] })
  type: string;

  @Column({ type: 'decimal', precision: 10, scale: 2, nullable: true })
  value: number; // pourcentage ou montant fixe

  @Column({ type: 'decimal', precision: 10, scale: 2, nullable: true })
  minAmount: number;

  @Column({ type: 'timestamp' })
  validFrom: Date;

  @Column({ type: 'timestamp' })
  validUntil: Date;

  @Column({ default: 0 })
  usageCount: number;

  @Column({ nullable: true })
  maxUses: number;

  @Column({ default: true })
  isActive: boolean;

  @CreateDateColumn()
  createdAt: Date;
}
```
Justification : `decimal` pour les valeurs monétaires, `enum` pour les types de coupon, `timestamp` pour les dates de validité, compteurs d'utilisation pour limiter la promotion.

