function calculateDiscountedTotal(
  subtotal: number,
  coupon: Coupon | null
): { discount: number; newSubtotal: number } {
  if (!coupon) {
    return { discount: 0, newSubtotal: subtotal };
  }

  let discount = 0;
  let newSubtotal = subtotal;

  switch (coupon.type) {
    case 'PERCENT':
      discount = subtotal * (coupon.value / 100);
      newSubtotal = subtotal - discount;
      break;

    case 'FIXED':
      discount = Math.min(coupon.value, subtotal); // Ne pas dépasser le sous-total
      newSubtotal = subtotal - discount;
      break;

    case 'FREE_SHIPPING':
      // Pas de réduction sur le sous-total, discount = 0
      discount = 0;
      newSubtotal = subtotal;
      break;
  }

  return { discount, newSubtotal };
}
